  2418→  auto type() const -> detail::type { return type_; }
  2419→
  2420→  /**
  2421→   * Visits an argument dispatching to the appropriate visit method based on
  2422→   * the argument type. For example, if the argument type is `double` then
  2423→   * `vis(value)` will be called with the value of type `double`.
  2424→   */
  2425→  template <typename Visitor>
  2426→  FMT_CONSTEXPR FMT_INLINE auto visit(Visitor&& vis) const -> decltype(vis(0)) {
  2427→    using detail::map;
  2428→    switch (type_) {
  2429→    case detail::type::none_type:        break;
  2430→    case detail::type::int_type:         return vis(value_.int_value);
  2431→    case detail::type::uint_type:        return vis(value_.uint_value);
  2432→    case detail::type::long_long_type:   return vis(value_.long_long_value);
  2433→    case detail::type::ulong_long_type:  return vis(value_.ulong_long_value);
  2434→    case detail::type::int128_type:      return vis(map(value_.int128_value));
  2435→    case detail::type::uint128_type:     return vis(map(value_.uint128_value));
  2436→    case detail::type::bool_type:        return vis(value_.bool_value);
  2437→    case detail::type::char_type:        return vis(value_.char_value);
  2438→    case detail::type::float_type:       return vis(value_.float_value);
  2439→    case detail::type::double_type:      return vis(value_.double_value);
  2440→    case detail::type::long_double_type: return vis(value_.long_double_value);
  2441→    case detail::type::cstring_type:     return vis(value_.string.data);
  2442→    case detail::type::string_type:      return vis(value_.string.str());
  2443→    case detail::type::pointer_type:     return vis(value_.pointer);
  2444→    case detail::type::custom_type:      return vis(handle(value_.custom));
  2445→    }
  2446→    return vis(monostate());
  2447→  }
