  2467→template <typename Context> class basic_format_args {
  2468→ private:
  2469→  // A descriptor that contains information about formatting arguments.
  2470→  // If the number of arguments is less or equal to max_packed_args then
  2471→  // argument types are passed in the descriptor. This reduces binary code size
  2472→  // per formatting function call.
  2473→  ullong desc_;
  2474→  union {
  2475→    // If is_packed() returns true then argument values are stored in values_;
  2476→    // otherwise they are stored in args_. This is done to improve cache
  2477→    // locality and reduce compiled code size since storing larger objects
  2478→    // may require more code (at least on x86-64) even if the same amount of
  2479→    // data is actually copied to stack. It saves ~10% on the bloat test.
  2480→    const detail::value<Context>* values_;
  2481→    const basic_format_arg<Context>* args_;
  2482→  };
  2483→
  2484→  constexpr auto is_packed() const -> bool {
  2485→    return (desc_ & detail::is_unpacked_bit) == 0;
  2486→  }
  2487→  constexpr auto has_named_args() const -> bool {
  2488→    return (desc_ & detail::has_named_args_bit) != 0;
  2489→  }
  2490→
  2491→  FMT_CONSTEXPR auto type(int index) const -> detail::type {
  2492→    int shift = index * detail::packed_arg_bits;
  2493→    unsigned mask = (1 << detail::packed_arg_bits) - 1;
  2494→    return static_cast<detail::type>((desc_ >> shift) & mask);
  2495→  }
