    90→FMT_FUNC void format_error_code(detail::buffer<char>& out, int error_code,
    91→                                string_view message) noexcept {
    92→  // Report error code making sure that the output fits into inline_buffer_size
    93→  // to avoid dynamic memory allocation and potential bad_alloc.
    94→  out.try_resize(0);
    95→  static const char SEP[] = ": ";
    96→  static const char ERROR_STR[] = "error ";
    97→  // Subtract 2 to account for terminating null characters in SEP and ERROR_STR.
    98→  size_t error_code_size = sizeof(SEP) + sizeof(ERROR_STR) - 2;
    99→  auto abs_value = static_cast<uint32_or_64_or_128_t<int>>(error_code);
   100→  if (detail::is_negative(error_code)) {
   101→    abs_value = 0 - abs_value;
   102→    ++error_code_size;
   103→  }
   104→  error_code_size += detail::to_unsigned(detail::count_digits(abs_value));
   105→  auto it = appender(out);
   106→  if (message.size() <= inline_buffer_size - error_code_size)
   107→    fmt::format_to(it, FMT_STRING("{}{}"), message, SEP);
   108→  fmt::format_to(it, FMT_STRING("{}{}"), ERROR_STR, error_code);
   109→  FMT_ASSERT(out.size() <= inline_buffer_size, "");
   110→}
